firestore.rules:
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {
    // Players - read by username+pin combo, write by admin
    match /players/{playerId} {
      allow read: if true;
      allow write: if true;
    }

    // PCs - readable by all, writable by admins and kiosk
    match /pcs/{pcId} {
      allow read: if true;
      allow write: if true;
    }

    // Menu items - readable by all, writable by admins
    match /menu/{itemId} {
      allow read: if true;
      allow write: if true;
    }

    // Orders
    match /orders/{orderId} {
      allow read: if true;
      allow write: if true;
    }

    // Reservations
    match /reservations/{resId} {
      allow read: if true;
      allow write: if true;
    }

    // Admins - only authenticated admins
    match /admins/{adminId} {
      allow read: if request.auth != null;
      allow write: if false;
    }

    // Config
    match /config/{doc} {
      allow read: if true;
      allow write: if true;
    }
  }
}
